/**
 * Expected body JSON:
 * {
 *   "airtable_record_id": "rec....",                // legacy Appsmith field, still accepted
 *   "mushroomprocess_product_id": "PROD-...."      // preferred Postgres-era field
 * }
 */
const body = $json.body || $json;
const airtable_record_id = body.airtable_record_id || null;
const mushroomprocess_product_id = body.mushroomprocess_product_id || body.product_id || null;

if (!airtable_record_id && !mushroomprocess_product_id) {
  throw new Error('Missing airtable_record_id or mushroomprocess_product_id');
}

return [{ json: { airtable_record_id, mushroomprocess_product_id } }];

const row = $json || {};
if (row.ok !== true) {
  const error = row.error || 'product_update_failed';
  const details = [
    row.mushroomprocess_product_id ? `product_id=${row.mushroomprocess_product_id}` : null,
    row.requested_storage_location ? `requested_storage_location=${row.requested_storage_location}` : null,
    row.airtable_record_id ? `airtable_record_id=${row.airtable_record_id}` : null
  ].filter(Boolean).join(', ');
  throw new Error(`Postgres product update failed: ${error}${details ? ' (' + details + ')' : ''}`);
}
return [{ json: row }];
